const staticData = $getWorkflowStaticData('global');
staticData.processedIds = staticData.processedIds || [];

const newItems = [];
for (const item of $input.all()) {
    const msgId = item.json.conversationId || item.json.id;
    if (!staticData.processedIds.includes(msgId)) {
        newItems.push(item);
        staticData.processedIds.push(msgId);
    }
}

if (staticData.processedIds.length > 100) {
    staticData.processedIds = staticData.processedIds.slice(-100);
}

return newItems;

// ─────────────────────────────────────────────────────────────────────────────
// OPTION A: Single-read VIP check
//
// $input.all()  → rows from the Excel sheet (one item per row)
// $node["Deduplicate Threads"].all() → the deduplicated email batch
//
// Strategy:
//   1. Build a Set of VIP email addresses from the sheet (O(1) lookup).
//   2. Loop through the email batch and tag each item with isVip: true/false.
//   3. Return ONLY the VIP-tagged emails so the downstream pipeline is unchanged.
//
// This replaces both the old "Excel: VIP Lookup" (per-item) node AND the
// old "Is VIP?" IF node -- one API call, zero rate-limit risk.
// ─────────────────────────────────────────────────────────────────────────────

// Step 1: Build the VIP Set from the sheet rows.
// ⚠️  ACTION REQUIRED: Change 'email' below to match your actual column header.
const VIP_COLUMN = 'email';

const vipSet = new Set(
    $input.all()
        .map(row => (row.json[VIP_COLUMN] || '').toString().toLowerCase().trim())
        .filter(Boolean)
);

// Step 2: Grab the email batch from the upstream Deduplicate node.
const emails = $node["Deduplicate Threads"].all();

if (!emails || emails.length === 0) {
    // Nothing to process -- stop cleanly.
    return [];
}

// Step 3: Tag each email and keep only VIPs.
const vipEmails = emails
    .map(item => {
        const senderAddress = (item.json?.from?.emailAddress?.address || '').toLowerCase().trim();
        return {
            json: {
                ...item.json,
                isVip: vipSet.has(senderAddress)
            }
        };
    })
    .filter(item => item.json.isVip);

return vipEmails;

return $input.all().map(item => {
    let aiData = { is_urgent: false, summary: "Parsing failed." };
    try {
        let raw = item.json.aiAnalysis?.message?.content || "{}";
        let clean = raw.replace(/```json/g, '').replace(/```/g, '').trim();
        aiData = JSON.parse(clean);
    } catch (e) {}

    return {
        json: {
            ...item.json,
            is_urgent: aiData.is_urgent ?? false,
            summary: aiData.summary ?? "Parsing failed."
        }
    };
});
